const { main, weather } = msg.payload;

const temp = main.temp;
const humidity = main.humidity;
const desc = weather[0].description;
const icon = weather[0].icon;


let autoCommand = "";

if (humidity <= 60) {
    autoCommand = "on";         // 60%以下なら「運転（加湿）」
} else if (humidity >= 65) {
    autoCommand = "dehumidify"; // 65%以上なら「除湿」
} else {
    autoCommand = "off";        // それ以外（61〜64%）は「停止」
}
// ------------------------------

msg.payload = {
    temp: Math.round(temp * 10) / 10,
    weather: desc,
    iconUrl: `http://openweathermap.org/img/wn/${icon}@2x.png`,
    value: autoCommand
};

return msg;

const value = msg.payload.value;
var epc;
var edt;

if (value == "on") {
    epc = 0x80;
    edt = 0x30;
    global.set("0x80", "0x30");
} else if (value == "off") {
    epc = 0x80;
    edt = 0x31;
    global.set("0x80", "0x31"); 
} else {
    return;
}

msg.els = {
    "ip": "127.0.0.1",          
    "tid": 1,
    "seoj": [0x05ff, 0x01],
    "deoj": [0x0130, 0x01],     
    "esv": 0x61,
    "epc": epc,
    "edt": [edt]
};
return msg;

// Send ECHONET Lite packet
// Assumption: OPC = 1
//
//  Usage:
//      Input following data
//
//  msg.els.ip      // ip address (String)
//  msg.els.tid     // TID (Int)
//  msg.els.seoj    // SEOJ ([Int:device, Int:instance])
//  msg.els.deoj    // DEOJ ([Int:device, Int:instance])
//  msg.els.esv     // ESV (Int)
//  msg.els.epc     // EPC (Int)
//  msg.els.edt     // EDT ([Int])
